api.code:
// API call with fetch (async)
return (async () => {
  const { url, method = 'GET' } = params

  try {
    const response = await fetch(url, {
      method,
      headers: {
        'Content-Type': 'application/json'
      }
    })

    const data = await response.json()
    return data
  } catch (error) {
    throw new Error(`API request failed: ${error.message}`)
  }
})()

