// Data processing example
const { data, operation } = params

switch (operation) {
  case 'filter':
    return data.filter((item) => item.active === true)

  case 'map':
    return data.map((item) => ({
      id: item.id,
      name: item.name
    }))

  case 'reduce':
    return data.reduce((acc, item) => acc + item.value, 0)

  default:
    throw new Error('Unknown operation type')
}
